class Solution {
    public int minStable(int[] nums, int maxC) {
        int n = nums.length;
        int[] count = new int[n];
        for (int i = 0; i < n; i++) {
            if (nums[i] % 2 == 0) count[i] = 1;
            if (i > 0) count[i] += count[i - 1];
        }
        int maxLen = 0;
        for (int i = 0; i < n; i++) {
            int lo = i, hi = n - 1;
            while (lo <= hi) {
                int mid = lo + (hi - lo) / 2;
                if (check(nums, count, i, mid)) {
                    lo = mid + 1;
                } else {
                    hi = mid - 1;
                }
            }
            maxLen = Math.max(maxLen, hi - i + 1);
        }
        return Math.max(1, maxLen - maxC);
    }

    private boolean check(int[] nums, int[] count, int i, int j) {
        int evenCount = count[j];
        if (i > 0) evenCount -= count[i - 1];
        return evenCount <= (j - i + 1) / 2;
    }
}
